target datalayout = "e-p:64:64:64"

; Function Attrs: nounwind
define void @yes(i1 %c, ptr %p, ptr %p1, ptr %q) #0 {
entry:
  store i32 0, ptr %p, align 4, !tbaa !0
  store i32 1, ptr %p1, align 4, !tbaa !3
  br i1 %c, label %if.else, label %if.then

if.then:                                          ; preds = %entry
  %t = load i32, ptr %p, align 4, !tbaa !0
  store i32 %t, ptr %q, align 4
  ret void

if.else:                                          ; preds = %entry
  ret void
}

attributes #0 = { nounwind }

!0 = !{!1, !1, i64 0}
!1 = !{!"red", !2}
!2 = !{}
!3 = !{!4, !4, i64 0}
!4 = !{!"blu", !2}

target datalayout = "e-p:64:64:64"

; Function Attrs: nounwind
define void @watch_out_for_type_change(i1 %c, ptr %p, ptr %p1, ptr %q) #0 {
entry:
  store i32 0, ptr %p, align 4, !tbaa !0
  store i32 1, ptr %p1, align 4, !tbaa !3
  br i1 %c, label %if.else, label %if.then

if.then:                                          ; preds = %entry
  %t = load i32, ptr %p, align 4, !tbaa !5
  store i32 %t, ptr %q, align 4
  ret void

